var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어때요, 박스 군? 자기가 만든 캐릭터가 움직이는 소감은?","JPN":"どうかな？　ダンボール君。自分で作ったキャラクターが動く感想は。","ENG":"So, Box. How does it feel to see your creation brought to life?","TWN":"怎麼樣，紙箱小朋友？看到自己製作的角色動起來，感覺如何？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……이런 건 처음이에요.","JPN":"……こんなのは初めてです。","ENG":"...I never experienced anything like this before.","TWN":"……我第一次有這種感覺。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그동안 항상 저 혼자서만 그림 그리고 겨우 인터넷에 올리는 게 전부였는데…….","JPN":"今まではいつも僕一人で描いて、ネットに投稿するだけでしたけど……","ENG":"All I ever did was to draw by myself and post them on the internet...","TWN":"過去我都是自己一個人畫畫，頂多就是上傳到網路上……"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"모두의 힘을 합해서 캐릭터를 움직이게 하는 거 정말 즐거운 것 같아요!","JPN":"みんな力を合わせてキャラを動かせるのって、本当に楽しいです！","ENG":"It feels great to team up and put it all together!","TWN":"像這樣大家一起同心合力讓角色動起來，真的好熱血！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그렇죠? 좋은 게임을 만들기 위해서는 먼저 개발자 스스로가 즐거워야 한다고 생각하거든요.","JPN":"はは、そうだろう？　いいゲームを作るためには、まず開発者が楽しくないとね。","ENG":"Ha ha, it does. Good games are made when the developers are actually having fun.","TWN":"哈哈，是吧？我認為自己必須先樂在其中，才能夠製作出好遊戲。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 혹시 괜찮다면, 한 가지 더 제안을 드리고 싶네요.","JPN":"それでなんだが、よければもう一つ提案したい。","ENG":"If it’s okay with you, I’d like to propose another offer.","TWN":"所以你不介意的話，我想再跟你商量一下。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"박스 군, 저희 학생들과 함께 게임을 제작해보는 건 어떨까요?","JPN":"ダンボール君、私の生徒と共にゲームを制作してみないか？","ENG":"Would you like to be a part of our team, Box?","TWN":"紙箱小朋友，你要試著和我的學生們一起製作遊戲嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마 박스 군에게도 잊지 못할 소중한 경험이 될 겁니다.","JPN":"多分、ダンボール君にも忘れられない大事な経験になると思うんだ。","ENG":"I think it’ll be an invaluable experience for you as well.","TWN":"我相信這對你而言會成為一個難忘的寶貴經驗。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네!? 제가 게임 제작이요!?","JPN":"はい！？　僕が、ゲーム制作を！？","ENG":"Me?! In the team?!","TWN":"真的嗎？我要製作遊戲嗎！？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와, 대단해! 박스 군의 실력이라면 우리 다음 코미페까지 카운터즈 사가를 완성할 수 있을지도 몰라!","JPN":"わあ、すごい！　ダンボール君の腕も加われば、私たち次のコミフェまでカウンターズ・サーガを完成できるかもしれない！","ENG":"Yes! With your artistry, we might be able to finish Counters Saga by next year’s Comic Festival!","TWN":"哇，好厲害喔！有你加入的話，說不定可以在下一屆動漫展前完成制裁者傳奇欸！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하고 싶은 걸지도…… 코미페 완판.","JPN":"やりたいかも……コミフェ、完売。","ENG":"To be sold out at Comic Festival… Maybe we want.","TWN":"有點想……動漫展完售。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 그게 좋네!","JPN":"へへっ、それええな！","ENG":"Heh, sounds good!","TWN":"嘿嘿，那好唄！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"마, 박스! 니 분명, 니 입으로 그랬다 아이가.","JPN":"おい、ダンボール！　あんた確かに自分の口でこう言うたよな？","ENG":"You, Box! Ya said it yourself, didn’t ya?","TWN":"喂，紙箱！不是你說的嗎！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"우리가 만든 게임은 사람들을 실망시킬 거라고……","JPN":"ウチらが作ったゲームに、みんながガッカリするて……","ENG":"That our game will disappoint the fans...","TWN":"我們做的遊戲會讓玩家失望……"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그리고 스트리트 카운터는 니한테 무척 소중한 게임이라고……!","JPN":"そしてストリート・カウンターは、あんたにとってとっても大事なゲームやって……！","ENG":"And that Street Counter is somethin’ dear to ya!","TWN":"還說什麼你很熱愛街頭制裁者……！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼 우리 연구회에 들어와서 니 스스로 직접 게임을 바꾸는기다!","JPN":"じゃあ、うちの研究会に入って自分の手でゲームを変えるんや！","ENG":"So come join our club, and you can make the game better!","TWN":"那你就加入我們研究社，自己親手改變遊戲吧！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...Huh?","TWN":"……什麼？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 물론 순순히 니 맘처럼은 안 될끼다. 우리는 우리가 맹글고 싶은대로 맹글거거든.","JPN":"へへっ、もちろん簡単にあんたの思いどおりにはいかへんで。ウチらは自分たちの作りたいように作るからな。","ENG":"Heh, I reckon it ain’t gonna be easy. We like doin’ things our way.","TWN":"嘿嘿，不過當然不是完全照你的意思，我們會繼續製作我們想要的遊戲。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그러니까 그게 싫으면 우리를 설득시켜가 게임을 더 좋은 방향으로 이끄는기다!","JPN":"だからそれがイヤなら、ウチらを説得してゲームをもっといい方向に導くんや！","ENG":"That’s why you should join and convince us all, to make a better game!","TWN":"要是你不喜歡，就說服我們，讓遊戲可以朝更好的方向前進唄！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"우얄래? 우리 서브 컬처 연구회랑 같이 게임 한 번 맹글어 볼래?","JPN":"どないする？　サブカルチャー研究会と一緒に、ゲームを作ってみいひん？","ENG":"How does that sit with ya? Would you like to join the Subculture Research Club?","TWN":"如何？要和我們二次元研究社一起做遊戲嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that’s...","TWN":"這……"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와? 쫄리나? 헤헷, 그럼 우리 맘대로 맹글어도 되는기제, 차기작?","JPN":"何や？　ビビってんの？　へへっ、じゃあ、ウチらの好きに続編作っていいんやな？","ENG":"Chickenin’ out? So you’re sayin’ you’re good with whatever we come up with, huh?","TWN":"怎麼？怕啦？嘿嘿，那續作就隨便我們囉？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"조, 좋아요! 게임 제작, 한 번 해볼게요!","JPN":"い、いいですよ！　ゲーム制作、やります！","ENG":"O-okay, okay! I'll do it!","TWN":"我…好啦！我願意試試看！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저는 미리네 누나처럼 대충대충 넘어가지 않을 거라고요!","JPN":"僕はマリさんみたいに適当にはしませんから！","ENG":"But I won’t let things slide like you do, Rinae!","TWN":"我才不會像宓璃奈姊姊那樣隨隨便便的！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"스트리트 카운터의 차기작이라는 이름에 걸맞은 멋진 게임을 만들거예요!","JPN":"ストリート・カウンターの続編という名に相応しい、素晴らしいゲームを作ってみせます！","ENG":"I’m going to make a cool game that lives up to the legacy of Street Counter!","TWN":"我要做出名符其實的街頭制裁者續作！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐라카노. 게임 그거 혼자 맹그는 거 아니라고! 모두 같이 만드는 거지!","JPN":"何言うてんねん。ゲームって、一人で作るんやないて言うたやん！　みんなで一緒に作るんやって！","ENG":"Whaddaya babblin’ about? It’s \\"we\\", not \\"you\\"! We’re in this together!","TWN":"說啥呢你，是我們要一起做好嗎？不是你自己一個人啦！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L38_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"좋아! 이제부터 박스X는 우리 서브컬처 연구회의 일러스트레이터래이!","JPN":"よし！　これからダンボールXは私たちサブカルチャー研究会のイラストレーターや！","ENG":"All right! Startin’ now, Box X is the official illustrator of the Subculture Research Club!","TWN":"好！我宣布，現在起BOX X就是我們二次元研究社的繪師！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L39_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이왕 맹그는 거 기깔나게 맹글어서 다음 코미페에 대박 한 번 쳐보는기다!","JPN":"どうせ作るなら、カッコよく作って次のコミフェで大成功させてみるんや！","ENG":"Let’s make this work wonders and make it all git-out!","TWN":"既然要做就要做到最好，要在下一屆動漫展一砲而紅！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 다들 보기 좋군요. 그럼 이런 건 어떨까요?","JPN":"はは、いいね。じゃあ、こんなのはどうかな。","ENG":"Ha ha, I see everyone is happy. Now, how does this sound?","TWN":"哈哈，大家都興致高昂的呢，那不如這樣吧？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여러분이 힘을 모아 만든 첫 캐릭터, <color=#ffd34c>미리네</color>를 주인공으로 게임을 만드는 거죠.","JPN":"みんなが力を合わせて作った初キャラクター、<color=#ffd34c>マリ</color>を主人公にしたゲームを作るんだ。","ENG":"We’re going to make your first collaborated character, <color=#ffd34c>Mi Rinae</color>, as the protagonist of the sequel.","TWN":"就以大家合力製作的第一個角色<color=#ffd34c>宓璃奈</color>為主角來製作遊戲吧！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금이야말로, 제 이야기가 아닌 여러분의 이야기……","JPN":"今こそ私の物語ではなく、みんなの物語……","ENG":"Now is the time to create your own story...","TWN":"現在起，不再是屬於我的故事，而是屬於你們自己的故事……"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"진짜 <color=#ffd34c>카운터즈 사가</color>를 만들어 보는 겁니다.","JPN":"本物の<color=#ffd34c>カウンターズ・サーガ</color>を作るんだ。","ENG":"The real <color=#ffd34c>Counters Saga</color>.","TWN":"這才是真正的<color=#ffd34c>制裁者傳奇</color>！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L47_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"좋은 생각인 것 같아요, 선생님!","JPN":"いいですね、先生！","ENG":"That sounds like a great idea, Teacher!","TWN":"老師的點子很棒欸！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와아! 제 캐릭터가 카운터즈 사가의 주인공이라고요!? 쌤, 정말요!?","JPN":"わあ！　ウチのキャラがカウンターズ・サーガの主人公！？　先生、マジで！？","ENG":"Whoa! My character as the protagonist of Counters Saga?! Really, Teach?!","TWN":"哇！我的角色是制裁者傳奇的主角嗎！？老師，你沒跟我開玩笑唄！？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L1_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나 캐릭터라니요! 이건 제가 그린 미리네라고요!","JPN":"マリさんのキャラじゃないです！　これは僕が描いたマリですよ！","ENG":"\\"Your\\" character? I’m the one who drew Mi Rinae!","TWN":"什麼姊姊的角色！那是我畫的宓璃奈好嗎！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L2_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"미리네? 꼬맹이가 어디서 반말이고! 글고 이건 내를 그렸으니까 내 캐릭터 맞다 아이가!","JPN":"マリ？　じゃりんこのくせに呼び捨てするん！？　それに、これはウチをモデルに描いたんやしウチのキャラやで！","ENG":"Don’t pull that attitude on me, ya little brat! Besides, I’m the model of the character! It’s obvious that she’s mine!","TWN":"宓璃奈？你這小子竟然敢叫我的全名！而且你是照著我的樣子畫的，當然是我的唄！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니는 초상권도 모르나? 초상권!","JPN":"あんた、肖像権って知らんの？　肖像権！","ENG":"Ever heard of personality right? Personality! Right!","TWN":"你沒聽過肖像權嗎？肖像權！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"무슨 소리에요! 제가 그렸으니까 이건 제 캐릭터라고요!","JPN":"何言ってるんですか！　僕が描いたんですから、これは僕のキャラですって！","ENG":"What are you talking about? She’s mine because she’s my creation!","TWN":"才不是咧！是我畫的當然是我的！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나는 저작권 모르세요? 저작권?","JPN":"マリさんは著作権を知らないんですか？　著作権！","ENG":"Ever heard of copyright? Copy. Right.","TWN":"姊姊沒聽過著作權嗎？著作權！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L8_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하하…… 다들 무슨 소리야. 이 귀여운 미리네는 우리 모두의 것인 걸?","JPN":"はは……みんな、何言ってるの。このかわいいいマリちゃんは私たちみんなのものだよ。","ENG":"Ha ha... What are you talking about? Our sweet little Rinae is for everyone to share.","TWN":"哈哈……都不是，這個可愛的宓璃奈是我們大家的！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그카지마라……. 니가 그카면 섬뜩하니까.","JPN":"やめてや……あんたがそんなこと言うとゾッとするねん。","ENG":"Stop... It ain’t so sweet when you’re the one sayin’ it.","TWN":"別這樣……這話從你口裡說出來特別可怕。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후후, 미리네가 게임 캐릭터로 나오면 진짜 귀여울 거 같아! 그렇지, 보라야?","JPN":"ふふ、マリちゃんがゲームのキャラクターで出たら、本当にかわいいと思う！　ねえ、シホちゃん？","ENG":"Fu fu. It’ll be so cute looking at Rinae as a playable character! Don’t you agree, Bora?","TWN":"呵呵，宓璃奈化身為遊戲裡的角色，感覺真的很可愛！你說是嗎，寶拉？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"될 거 같아…… 미리네가 게임 주인공이라면.","JPN":"なりそう……マリがゲームの主人公なら。","ENG":"If Mi Rinae becomes the main character... It’ll become...","TWN":"好像會…… 宓璃奈當遊戲主角。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐꼬, 그기 뭔 뜻인데? 내가 주인공이면 뭐가 된다고?","JPN":"何や、それどういう意味やねん？　ウチが主人公ならどないなるんや？","ENG":"Huh? Become what? Would ya finish that sentence for me?","TWN":"什麼什麼？我當主角的話會什麼？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하, 혹시 그런기가!? 내 매력 때문에 우리 게임이 잘 될 거라는 뜻?","JPN":"あ、もしかしてそれ！？　ウチの魅力のおかげで、このゲームが大ヒットするってこと？","ENG":"Oh! You mean become super famous? Thanks to my charm?! Heh!","TWN":"喔～是這個意思唄！？遊戲會因為我的魅力而大賣嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L21_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아니……. 될 거 같아.","JPN":"違う……なりそう。","ENG":"No... It’ll become...","TWN":"不是……是會變成，"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……메리 수.","JPN":"……メアリー・スー。","ENG":"...Mary Sue.","TWN":"……自戀狂。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};